bedrock = boto3.client('bedrock-agent-runtime')

def invoke_agent_with_pii_monitor(agent_id, session_id, input_text):
    try:
        response = bedrock.invoke_agent(
            agentId=agent_id,
            agentAliasId='latest',
            sessionId=session_id,
            inputText=input_text
        )

        # Check action group results in trace
        trace = response['completion']
        if 'actionGroups' in response['trace']:
            for action in response['trace']['actionGroups']:
                if 'observation' in action and len(action['observation']) > 500:
                    print('⚠️  Potential raw data leak in action group')
        return response
    except ClientError as e:
        print(f'Agent invocation failed: {e}')
        return None

