def sanitize_pii(data):
    # Replace PII patterns
    data['customer_ssn'] = '***-**-****'
    data['email'] = data['email'].split('@')[0] + '@redacted.com'
    return data

import boto3

bedrock_kb = boto3.client('bedrock-agent-runtime')

FORBIDDEN_DOMAINS = ['hr.internal', 'confidential']

def filter_kb_response(kb_response):
    filtered_chunks = []
    for chunk in kb_response['retrievalResults']:
        content = chunk['content']['text']
        # Skip chunks from internal domains
        if not any(domain in content for domain in FORBIDDEN_DOMAINS):
            filtered_chunks.append(chunk)
    return {'retrievalResults': filtered_chunks}

